        <div class="dialog-actions">
            <button class="btn btn-secondary" @onclick="() => _showRevokeConfirm = false">Cancel</button>
            <button class="btn btn-danger" @onclick="ConfirmRevokeSession">Revoke</button>
        </div>
    </div>
}

@code {
    // ── Section navigation ──────────────────────────────────────────

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // ── Toast ───────────────────────────────────────────────────────

    private bool _showToast;
    private string _toastMessage = "";
    private string _toastType = "success";
    private CancellationTokenSource? _toastCts;

    private async Task ShowToast(string message, string type = "success")
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastType = type;
        _showToast = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _showToast = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Profile ─────────────────────────────────────────────────────

    private UserProfile? _profile;
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editBio = "";
    private string _editAvatarUrl = "";

    // ── Notifications ───────────────────────────────────────────────

    private NotificationPrefs? _notifPrefs;
    private bool _editEmailNotif;
    private bool _editPushNotif;
    private bool _editWeeklyDigest;
    private HashSet<string> _editMutedChannels = new();
    private static readonly List<string> AllChannels =
        ["general", "announcements", "random", "dev-team", "design", "support"];

    // ── Security ────────────────────────────────────────────────────

    private SecuritySettings? _security;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _showRevokeConfirm;
    private ActiveSession? _sessionToRevoke;

