    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;
    private static readonly string[] Themes = ["Light", "Dark", "System"];
    private static readonly string[] FontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    // ── Lifecycle ───────────────────────────────────────────────────

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _savedProfile = _profile;
        SetProfileEditFields(_profile);

        _notifPrefs = notifTask.Result;
        SetNotifEditFields(_notifPrefs);

        _security = securityTask.Result;

        _appearance = appearanceTask.Result;
        SetAppearanceEditFields(_appearance);

        _loading = false;
    }

    // ── Profile helpers ─────────────────────────────────────────────

    private void SetProfileEditFields(UserProfile p)
    {
        _editDisplayName = p.DisplayName;
        _editEmail = p.Email;
        _editBio = p.Bio;
        _editAvatarUrl = p.AvatarUrl;
    }

    private async Task SaveProfile()
    {
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _savedProfile = updated;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            SetProfileEditFields(_savedProfile);
    }

    // ── Notification helpers ────────────────────────────────────────

    private void SetNotifEditFields(NotificationPrefs n)
    {
        _editEmailNotif = n.EmailNotifications;
        _editPushNotif = n.PushNotifications;
        _editWeeklyDigest = n.WeeklyDigest;
        _editMutedChannels = new HashSet<string>(n.MutedChannels);
    }

    private void ToggleChannelMute(string channel, object? value)
    {
        if (value is bool muted && muted)
            _editMutedChannels.Add(channel);
        else
            _editMutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var updated = new NotificationPrefs(_editEmailNotif, _editPushNotif, _editWeeklyDigest, _editMutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _notifPrefs = updated;
        await ShowToast("Notification preferences saved!");
    }

    // ── Security helpers ────────────────────────────────────────────

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword != _confirmPassword)
        {
            await ShowToast("Passwords do not match.", "error");
            return;
        }
        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            await ShowToast("Current password is required.", "error");
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        await ShowToast("Password updated successfully!");
    }

    private void RequestRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeConfirm = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _security = await SettingsService.GetSecuritySettingsAsync();
            _showRevokeConfirm = false;
            _sessionToRevoke = null;
            await ShowToast("Session revoked.");
