@page "/settings"
@using sv_ea3339feefd74461936372823c9c32ca.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

@* Toast notification *@
@if (_showToast)
{
    <div class="settings-toast @(_toastType)">
        <span>@_toastMessage</span>
        <button class="toast-close" @onclick="() => _showToast = false">✕</button>
    </div>
}

@* Session revoke confirmation dialog *@
@if (_showRevokeConfirm)
{
    <div class="modal-backdrop" @onclick="() => _showRevokeConfirm = false"></div>
    <div class="confirm-dialog">
        <h5>Revoke Session</h5>
        <p>Are you sure you want to revoke this session on <strong>@_sessionToRevoke?.Device</strong>?
            The user will be signed out immediately.</p>
        <div class="dialog-actions">
            <button class="btn btn-secondary" @onclick="() => _showRevokeConfirm = false">Cancel</button>
            <button class="btn btn-danger" @onclick="ConfirmRevokeSession">Revoke</button>
        </div>
    </div>
}

@code {
    // ── Section navigation ──────────────────────────────────────────

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // ── Toast ───────────────────────────────────────────────────────

    private bool _showToast;
    private string _toastMessage = "";
    private string _toastType = "success";
    private CancellationTokenSource? _toastCts;

    private async Task ShowToast(string message, string type = "success")
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastType = type;
        _showToast = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _showToast = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Profile ─────────────────────────────────────────────────────

    private UserProfile? _profile;
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editBio = "";
    private string _editAvatarUrl = "";

    // ── Notifications ───────────────────────────────────────────────

    private NotificationPrefs? _notifPrefs;
    private bool _editEmailNotif;
    private bool _editPushNotif;
    private bool _editWeeklyDigest;
    private HashSet<string> _editMutedChannels = new();
    private static readonly List<string> AllChannels =
        ["general", "announcements", "random", "dev-team", "design", "support"];

    // ── Security ────────────────────────────────────────────────────

    private SecuritySettings? _security;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _showRevokeConfirm;
    private ActiveSession? _sessionToRevoke;

    // ── Appearance ──────────────────────────────────────────────────

    private AppearanceSettings? _appearance;
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;
    private static readonly string[] Themes = ["Light", "Dark", "System"];
    private static readonly string[] FontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    // ── Lifecycle ───────────────────────────────────────────────────

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _savedProfile = _profile;
        SetProfileEditFields(_profile);

        _notifPrefs = notifTask.Result;
        SetNotifEditFields(_notifPrefs);

        _security = securityTask.Result;

        _appearance = appearanceTask.Result;
        SetAppearanceEditFields(_appearance);

        _loading = false;
    }

    // ── Profile helpers ─────────────────────────────────────────────

    private void SetProfileEditFields(UserProfile p)
    {
        _editDisplayName = p.DisplayName;
        _editEmail = p.Email;
        _editBio = p.Bio;
        _editAvatarUrl = p.AvatarUrl;
    }

    private async Task SaveProfile()
    {
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _savedProfile = updated;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            SetProfileEditFields(_savedProfile);
    }

    // ── Notification helpers ────────────────────────────────────────

    private void SetNotifEditFields(NotificationPrefs n)
    {
        _editEmailNotif = n.EmailNotifications;
        _editPushNotif = n.PushNotifications;
        _editWeeklyDigest = n.WeeklyDigest;
        _editMutedChannels = new HashSet<string>(n.MutedChannels);
    }

    private void ToggleChannelMute(string channel, object? value)
    {
        if (value is bool muted && muted)
            _editMutedChannels.Add(channel);
        else
            _editMutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var updated = new NotificationPrefs(_editEmailNotif, _editPushNotif, _editWeeklyDigest, _editMutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _notifPrefs = updated;
        await ShowToast("Notification preferences saved!");
    }

    // ── Security helpers ────────────────────────────────────────────

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword != _confirmPassword)
        {
            await ShowToast("Passwords do not match.", "error");
            return;
        }
        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            await ShowToast("Current password is required.", "error");
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        await ShowToast("Password updated successfully!");
    }

    private void RequestRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeConfirm = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _security = await SettingsService.GetSecuritySettingsAsync();
            _showRevokeConfirm = false;
            _sessionToRevoke = null;
            await ShowToast("Session revoked.");
        }
    }

    // ── Appearance helpers ──────────────────────────────────────────

    private void SetAppearanceEditFields(AppearanceSettings a)
    {
        _editTheme = a.Theme;
        _editFontSize = a.FontSize;
        _editLanguage = a.Language;
        _editCompactMode = a.CompactMode;
    }

    private async Task SaveAppearance()
    {
        var updated = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _appearance = updated;
        await ShowToast("Appearance settings saved!");
    }

    private string PreviewFontSize => _editFontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.2rem",
        _ => "1rem"
    };

    private string PreviewBackground => _editTheme switch
    {
        "Dark" => "#1e1e2e",
        "System" => "#f0f0f5",
        _ => "#ffffff"
    };

    private string PreviewTextColor => _editTheme == "Dark" ? "#e0e0e0" : "#212529";

    // ── Render fragments ────────────────────────────────────────────

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Profile</h3>
            <p class="section-desc">Manage your personal information and public profile.</p>

            <div class="avatar-area">
                <div class="avatar-preview">
                    <img src="@_editAvatarUrl" alt="Avatar" />
                </div>
                <div class="avatar-url">
                    <label>Avatar URL</label>
                    <input type="text" class="form-control" @bind="_editAvatarUrl" />
                </div>
            </div>

            <div class="form-group">
                <label>Display Name</label>
                <input type="text" class="form-control" @bind="_editDisplayName" />
            </div>

            <div class="form-group">
                <label>Email</label>
                <input type="email" class="form-control" @bind="_editEmail" />
            </div>

            <div class="form-group">
                <label>Bio</label>
                <textarea class="form-control" rows="4" @bind="_editBio"></textarea>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Notifications</h3>
            <p class="section-desc">Control how and when you receive notifications.</p>

            <div class="toggle-row">
                <div class="toggle-info">
                    <span class="toggle-label">Email Notifications</span>
                    <span class="toggle-desc">Receive notifications via email</span>
                </div>
                <label class="switch">
                    <input type="checkbox" @bind="_editEmailNotif" />
                    <span class="slider"></span>
                </label>
            </div>

            <div class="toggle-row">
                <div class="toggle-info">
                    <span class="toggle-label">Push Notifications</span>
                    <span class="toggle-desc">Receive push notifications in your browser</span>
                </div>
                <label class="switch">
                    <input type="checkbox" @bind="_editPushNotif" />
                    <span class="slider"></span>
                </label>
            </div>

            <div class="toggle-row">
                <div class="toggle-info">
                    <span class="toggle-label">Weekly Digest</span>
                    <span class="toggle-desc">Get a weekly summary of activity</span>
                </div>
                <label class="switch">
                    <input type="checkbox" @bind="_editWeeklyDigest" />
                    <span class="slider"></span>
                </label>
            </div>

            <h5 class="mt-4">Muted Channels</h5>
            <p class="section-desc">Select channels to mute. You won't receive notifications from muted channels.</p>
            <div class="channel-list">
                @foreach (var channel in AllChannels)
                {
                    <label class="channel-item">
                        <input type="checkbox"
                               checked="@(_editMutedChannels.Contains(channel))"
                               @onchange="e => ToggleChannelMute(channel, e.Value)" />
                        <span class="channel-name">#@channel</span>
                        @if (_editMutedChannels.Contains(channel))
                        {
                            <span class="badge bg-secondary ms-auto">Muted</span>
                        }
                    </label>
                }
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
            </div>
        </section>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h3>Security</h3>
            <p class="section-desc">Manage your password, two-factor authentication, and active sessions.</p>

            @* Change Password Panel *@
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>🔑 Change Password</span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="panel-body">
                        @if (_security?.LastPasswordChange is not null)
                        {
                            <p class="text-muted small">
                                Last changed: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                            </p>
                        }
                        <div class="form-group">
                            <label>Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label>New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label>Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="ChangePassword">Update Password</button>
                    </div>
                }
            </div>

            @* Two-factor Authentication *@
            <div class="toggle-row mt-3">
                <div class="toggle-info">
                    <span class="toggle-label">Two-Factor Authentication</span>
                    <span class="toggle-desc">
                        @if (_security?.TwoFactorEnabled == true)
                        {
                            <span class="status-badge enabled">● Enabled</span>
                        }
                        else
                        {
                            <span class="status-badge disabled">● Disabled</span>
                        }
                    </span>
                </div>
                <label class="switch">
                    <input type="checkbox" checked="@(_security?.TwoFactorEnabled ?? false)" disabled />
                    <span class="slider"></span>
                </label>
            </div>

            @* Active Sessions *@
            <h5 class="mt-4">Active Sessions</h5>
            <div class="sessions-table">
                <table class="table">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_security?.Sessions is not null)
                        {
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrentSession = session == _security.Sessions[0];
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrentSession)
                                        {
                                            <span class="badge bg-success ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrentSession)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => RequestRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>
        </section>
    };

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Appearance</h3>
            <p class="section-desc">Customize how the application looks and feels.</p>

            @* Theme *@
            <div class="form-group">
                <label class="group-label">Theme</label>
                <div class="radio-group">
                    @foreach (var theme in Themes)
                    {
                        <label class="radio-option @(_editTheme == theme ? "selected" : "")">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_editTheme == theme)"
                                   @onchange="() => _editTheme = theme" />
                            <span class="radio-label">
                                @(theme switch { "Light" => "☀️", "Dark" => "🌙", _ => "🖥️" })
                                @theme
                            </span>
                        </label>
                    }
                </div>
            </div>

            @* Font Size *@
            <div class="form-group">
                <label class="group-label">Font Size</label>
                <div class="radio-group">
                    @foreach (var size in FontSizes)
                    {
                        <label class="radio-option @(_editFontSize == size ? "selected" : "")">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_editFontSize == size)"
                                   @onchange="() => _editFontSize = size" />
                            <span class="radio-label">@size</span>
                        </label>
                    }
                </div>
            </div>

            @* Language *@
            <div class="form-group">
                <label class="group-label">Language</label>
                <select class="form-select" @bind="_editLanguage">
                    @foreach (var lang in Languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            @* Compact Mode *@
            <div class="toggle-row">
                <div class="toggle-info">
                    <span class="toggle-label">Compact Mode</span>
                    <span class="toggle-desc">Reduce spacing and padding for a denser layout</span>
                </div>
                <label class="switch">
                    <input type="checkbox" @bind="_editCompactMode" />
                    <span class="slider"></span>
                </label>
            </div>

            @* Live Preview *@
            <div class="form-group">
                <label class="group-label">Preview</label>
                <div class="live-preview" style="background:@PreviewBackground;color:@PreviewTextColor;font-size:@PreviewFontSize;padding:@(_editCompactMode ? "0.5rem" : "1.25rem");">
                    <h5 style="color:@PreviewTextColor;margin-bottom:@(_editCompactMode ? "0.25rem" : "0.75rem");">Dashboard</h5>
                    <p style="margin-bottom:@(_editCompactMode ? "0.25rem" : "0.5rem");">Welcome back, Jane! You have <strong>3 new notifications</strong>.</p>
                    <div class="preview-cards" style="gap:@(_editCompactMode ? "0.4rem" : "0.75rem");">
                        <div class="preview-card" style="background:@(_editTheme == "Dark" ? "#2d2d3f" : "#f8f9fa");padding:@(_editCompactMode ? "0.4rem 0.6rem" : "0.75rem 1rem");">
                            📊 Analytics
                        </div>
                        <div class="preview-card" style="background:@(_editTheme == "Dark" ? "#2d2d3f" : "#f8f9fa");padding:@(_editCompactMode ? "0.4rem 0.6rem" : "0.75rem 1rem");">
                            📝 Recent Activity
                        </div>
                        <div class="preview-card" style="background:@(_editTheme == "Dark" ? "#2d2d3f" : "#f8f9fa");padding:@(_editCompactMode ? "0.4rem 0.6rem" : "0.75rem 1rem");">
                            👥 Team Members
                        </div>
                    </div>
                </div>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </section>
    };
}

