    cursor: pointer;
    color: #555;
    font-weight: 500;
    transition: all 0.15s ease;
    border-left: 3px solid transparent;
}

.settings-nav .nav-item:hover {
    background: #f0f2f8;
    color: #333;
}

.settings-nav .nav-item.active {
    background: #eef1fb;
    color: #4361ee;
    border-left-color: #4361ee;
    font-weight: 600;
}

.nav-icon {
    font-size: 1.15rem;
}

/* ── Content ───────────────────────────────────────────────────── */

.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    overflow-y: auto;
}

.settings-section h3 {
    margin: 0 0 0.25rem;
    font-weight: 700;
    font-size: 1.35rem;
}

.section-desc {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

.loading-spinner {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 4rem;
}

