.form-group {
    margin-bottom: 1.25rem;
}

.form-group label,
.group-label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.35rem;
    color: #333;
    font-size: 0.9rem;
}

.form-control,
.form-select {
    max-width: 480px;
}

.button-group {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
    padding-top: 1.5rem;
    border-top: 1px solid #e9ecef;
}

