.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.85rem 1rem;
    background: #fff;
    border: 1px solid #e9ecef;
    border-radius: 0.5rem;
    margin-bottom: 0.75rem;
}

.toggle-info {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

.toggle-label {
    font-weight: 600;
    font-size: 0.95rem;
}

.toggle-desc {
    font-size: 0.82rem;
    color: #6c757d;
}

.switch {
